<span class="line"><span style="--shiki-light:#BFBDB6;--shiki-dark:#BFBDB6;">            smallest </span><span style="--shiki-light:#F29668;--shiki-dark:#F29668;">=</span><span style="--shiki-light:#BFBDB6;--shiki-dark:#BFBDB6;"> arr[i]</span></span>
